    pub fn run_session_posture_evidence(
        &self,
        store: &Ph1fStore,
        request: AppSessionPostureEvidenceRequest,
    ) -> Result<AppSessionPostureEvidenceOutcome, StorageError> {
        let AppSessionPostureEvidenceRequest {
            correlation_id: _,
            idempotency_key: _,
            device_id,
            session_id,
        } = request;

        let record = store
            .nonclosed_session_for_last_attached_device(&device_id, &session_id)
            .ok_or(StorageError::ContractViolation(
                ContractViolation::InvalidValue {
                    field: "app_session_posture_evidence_request.session_id",
                    reason: "SESSION_NOT_AVAILABLE_FOR_DEVICE",
                },
            ))?;

        let mut evidence = stored_session_posture_evidence(&record);
        if let Some(resume_selection) = stored_session_resume_selection_evidence(store, &record)? {
            evidence.selected_thread_id = resume_selection.selected_thread_id;
            evidence.selected_thread_title = resume_selection.selected_thread_title;
            evidence.pending_work_order_id = resume_selection.pending_work_order_id;
            evidence.resume_tier = resume_selection.resume_tier;
            evidence.resume_summary_bullets = resume_selection.resume_summary_bullets;
        }
        if let Some(archived_recent_slice) =
            stored_session_archived_recent_slice_evidence(store, &record)
        {
            evidence.archived_user_turn_text = Some(archived_recent_slice.archived_user_turn_text);
            evidence.archived_selene_turn_text =
                Some(archived_recent_slice.archived_selene_turn_text);
        }

        Ok(AppSessionPostureEvidenceOutcome { evidence })
    }

