fn canonical_recovery_identity_state_matches_shape(
    identity_state: &IdentityExecutionState,
    recovery_reason_code: ReasonCodeId,
) -> bool {
    match recovery_reason_code {
        code if code == voice_id_reason_codes::VID_REAUTH_REQUIRED
            || code == voice_id_reason_codes::VID_DEVICE_CLAIM_REQUIRED =>
        {
            identity_state.consistency_level
                == IdentityVerificationConsistencyLevel::RecoveryRestricted
                && identity_state.trust_tier == IdentityTrustTier::Restricted
                && identity_state.step_up_required
                && identity_state.recovery_state == IdentityRecoveryState::ReauthRequired
        }
        code if code == voice_id_reason_codes::VID_ENROLLMENT_REQUIRED
            || code == voice_id_reason_codes::VID_FAIL_PROFILE_NOT_ENROLLED =>
        {
            identity_state.consistency_level
                == IdentityVerificationConsistencyLevel::RecoveryRestricted
                && identity_state.trust_tier == IdentityTrustTier::Restricted
                && !identity_state.step_up_required
                && identity_state.recovery_state == IdentityRecoveryState::ReEnrollmentRequired
        }
        _ => false,
    }
}

