fn clean_weather_display_place(requested_place: &str, provider_place: &str) -> String {
    let requested = clean_weather_place_label(requested_place);
    let provider = clean_weather_place_label(provider_place);
    if weather_requested_place_is_specific(requested.as_str()) {
        requested
    } else {
        provider
    }
}

fn weather_requested_place_is_specific(place: &str) -> bool {
    let normalized = normalize_place_key(place);
    !matches!(
        normalized.as_str(),
        "" | "that place"
            | "there"
            | "there now"
            | "here"
            | "rain"
            | "raining"
            | "rainy"
            | "precipitation"
            | "snow"
            | "snowing"
            | "weather"
            | "forecast"
    ) && weather_country_ambiguity(place).is_none()
        && weather_broad_region_ambiguity(place).is_none()
}

fn json_number(values: &serde_json::Value, keys: &[&str]) -> Option<f64> {
    keys.iter()
        .find_map(|key| values.get(*key).and_then(serde_json::Value::as_f64))
}

fn json_i64(values: &serde_json::Value, keys: &[&str]) -> Option<i64> {
    keys.iter()
        .find_map(|key| values.get(*key).and_then(serde_json::Value::as_i64))
}

fn weather_forecast_day_label(day: &serde_json::Value) -> String {
    day.get("date")
        .and_then(serde_json::Value::as_str)
        .or_else(|| day.get("time").and_then(serde_json::Value::as_str))
        .or_else(|| day.get("startTime").and_then(serde_json::Value::as_str))
        .map(|value| value.chars().take(10).collect::<String>())
        .filter(|value| !value.trim().is_empty())
        .unwrap_or_else(|| "next day".to_string())
}

fn format_weather_forecast_entry(
    date: &str,
    temperature_c: f64,
    condition: &str,
    rain_chance: Option<f64>,
    rain_requested: bool,
) -> String {
    let condition = clean_weather_condition_label(condition);
    let condition = if condition.is_empty() {
        "conditions available".to_string()
    } else {
        condition
    };
    match rain_chance {
        Some(chance) if rain_requested || chance > 0.0 => format!(
            "{}: {}°C, {}, {}% rain chance",
            date,
            format_weather_number(temperature_c),
            condition,
            format_weather_number(chance)
        ),
        _ => format!(
            "{}: {}°C and {}",
            date,
            format_weather_number(temperature_c),
            condition
        ),
    }
}

fn format_weather_forecast_summary(place: &str, query: &str, entries: Vec<String>) -> String {
    let place = clean_weather_place_label(place);
    let label = if weather_query_asks_rain(query) {
        "rain forecast"
    } else {
        "forecast"
    };
    format!("{} {}: {}.", place, label, entries.join("; "))
}

fn clean_weather_sentence(
    place: &str,
    temperature_c: f64,
    condition: &str,
    humidity: Option<f64>,
    wind: Option<(f64, &str)>,
) -> String {
    let place = clean_weather_place_label(place);
    let condition = clean_weather_condition_label(condition);
    if condition.is_empty() {
        return format!("{} is {}°C.", place, format_weather_number(temperature_c));
    }
    let _ = (humidity, wind);
    format!(
        "{} is {}°C and {}.",
        place,
        format_weather_number(temperature_c),
        condition
    )
}

fn clean_weather_rain_sentence(place: &str, temperature_c: f64, condition: &str) -> String {
    let place = clean_weather_place_label(place);
    let condition = clean_weather_condition_label(condition);
    if condition.is_empty() {
        return format!(
            "{} is {}°C right now; I do not have a rain signal in the current conditions.",
            place,
            format_weather_number(temperature_c)
        );
    }
    if weather_condition_indicates_rain(condition.as_str()) {
        format!(
            "{} is {}°C with {} right now.",
            place,
            format_weather_number(temperature_c),
            condition
        )
    } else {
        format!(
            "{} is {}°C and {} right now, so current conditions do not indicate rain.",
            place,
            format_weather_number(temperature_c),
            condition
        )
    }
}

fn weather_condition_indicates_rain(condition: &str) -> bool {
    let normalized = normalize_place_key(condition);
    normalized.contains("rain")
        || normalized.contains("drizzle")
        || normalized.contains("shower")
        || normalized.contains("snow")
        || normalized.contains("thunderstorm")
        || normalized.contains("sleet")
        || normalized.contains("hail")
}

fn clean_weather_condition_label(condition: &str) -> String {
    let trimmed = condition.trim().trim_matches('.');
    if trimmed.is_empty() || trimmed.eq_ignore_ascii_case("current conditions") {
        return String::new();
    }
    let mut out = trimmed.to_string();
    if let Some(first) = out.get_mut(0..1) {
        first.make_ascii_lowercase();
    }
    out
}

fn clean_weather_place_label(place: &str) -> String {
    let trimmed = place
        .trim_matches(|ch: char| ch == '?' || ch == '.' || ch == ',' || ch == ';')
        .trim();
    if trimmed.is_empty() {
        return "that place".to_string();
    }
    let normalized = normalize_place_key(trimmed);
    if normalized == "悉尼" {
        return "Sydney".to_string();
    }
    if normalized == "巴塞罗那" || normalized == "巴塞隆拿" {
        return "Barcelona".to_string();
    }
    if normalized == "马德里" || normalized == "馬德里" {
        return "Madrid".to_string();
    }
    if normalized.contains("council of the city of sydney")
        || normalized == "city of sydney"
        || normalized == "sydney new south wales australia"
    {
        return "Sydney".to_string();
    }
    if normalized == "kunshan china" || normalized == "kunchan china" {
        return "Kunshan".to_string();
    }
    if normalized == "comunidad de madrid" || normalized == "community of madrid" {
        return "Madrid".to_string();
    }
    if normalized.starts_with("springfield ") {
        if normalized.contains("illinois") {
            return "Springfield, Illinois".to_string();
        }
        if normalized.contains("missouri") {
            return "Springfield, Missouri".to_string();
        }
        if normalized.contains("massachusetts") {
            return "Springfield, Massachusetts".to_string();
        }
    }
    let first = trimmed.split(',').next().unwrap_or(trimmed).trim();
    if first.is_empty() {
        trimmed.to_string()
    } else {
        first.to_string()
    }
}

fn format_weather_number(value: f64) -> String {
    if (value.fract()).abs() < 0.05 {
        format!("{}", value.round() as i64)
    } else {
        format!("{value:.1}")
    }
}

fn tomorrow_weather_code_label(code: i64) -> &'static str {
    match code {
        1000 => "clear",
        1100 => "mostly clear",
        1101 => "partly cloudy",
        1102 => "mostly cloudy",
        1001 => "cloudy",
        2000 | 2100 => "foggy",
        4000 => "drizzle",
        4001 => "rain",
        4200 => "light rain",
        4201 => "heavy rain",
        5000 => "snow",
        5001 => "flurries",
        5100 => "light snow",
        5101 => "heavy snow",
        6000 => "freezing drizzle",
        6001 => "freezing rain",
        6200 => "light freezing rain",
        6201 => "heavy freezing rain",
        7000 => "ice pellets",
        7101 => "heavy ice pellets",
        7102 => "light ice pellets",
        8000 => "thunderstorms",
        _ => "current conditions",
    }
}

fn weather_source_metadata_from_evidence(
    evidence_packet: &serde_json::Value,
) -> Result<SourceMetadata, ()> {
    let retrieved_at_unix_ms = evidence_packet
        .get("retrieved_at_ms")
        .and_then(serde_json::Value::as_i64)
        .filter(|value| *value > 0)
        .map(|value| value as u64)
        .ok_or(())?;
    let provider_hint = evidence_packet
        .pointer("/trust_metadata/realtime/payload/provider")
        .and_then(serde_json::Value::as_str)
        .map(|provider| {
            if provider == "tomorrow.io" {
                "tomorrow_io_weather".to_string()
            } else {
                "weatherapi_weather".to_string()
            }
        });
    let mut sources = Vec::new();
    if let Some(array) = evidence_packet
        .get("sources")
        .and_then(serde_json::Value::as_array)
    {
        for item in array.iter().take(5) {
            let title = item
                .get("title")
                .and_then(serde_json::Value::as_str)
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .unwrap_or("Weather provider evidence");
            let url = item
                .get("url")
                .and_then(serde_json::Value::as_str)
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .unwrap_or("https://selene.local/weather/evidence");
            sources.push(SourceRef {
                title: title.to_string(),
                url: url.to_string(),
            });
        }
    }
    if sources.is_empty() {
        sources.push(SourceRef {
            title: "Weather provider evidence".to_string(),
            url: "https://selene.local/weather/evidence".to_string(),
        });
    }
    Ok(SourceMetadata {
        schema_version: selene_kernel_contracts::ph1e::PH1E_CONTRACT_VERSION,
        provider_hint,
        retrieved_at_unix_ms,
        sources,
    })
}

fn app_ingress_unix_time_ms() -> i64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|duration| duration.as_millis() as i64)
        .unwrap_or(1)
}

fn maybe_build_list_reminders_tool_response(
    store: &Ph1fStore,
    actor_user_id: &UserId,
    ph1x_request: &Ph1xRequest,
    tool_request: &ToolRequest,
) -> Result<Option<ToolResponse>, StorageError> {
    if !matches!(tool_request.tool_name, ToolName::ConnectorQuery) {
        return Ok(None);
    }
    let is_list_reminders_intent = matches!(
        ph1x_request.nlp_output.as_ref(),
        Some(Ph1nResponse::IntentDraft(intent_draft))
            if intent_draft.intent_type == IntentType::ListReminders
    );
    if !is_list_reminders_intent && !is_list_reminders_query(tool_request.query.as_str()) {
        return Ok(None);
    }

    let mut reminders: Vec<_> = store
        .reminders()
        .values()
        .filter(|row| &row.user_id == actor_user_id)
        .collect();
    reminders.sort_by(|left, right| {
        left.resolved_due_at
            .0
            .cmp(&right.resolved_due_at.0)
            .then(left.created_at.0.cmp(&right.created_at.0))
            .then(left.reminder_id.as_str().cmp(right.reminder_id.as_str()))
    });

    let active_count = reminders
        .iter()
        .filter(|row| {
            !matches!(
                row.state,
                selene_kernel_contracts::ph1rem::ReminderState::Canceled
                    | selene_kernel_contracts::ph1rem::ReminderState::Completed
                    | selene_kernel_contracts::ph1rem::ReminderState::Failed
            )
        })
        .count();
    let next_active_due_at = reminders
        .iter()
        .find(|row| {
            !matches!(
                row.state,
                selene_kernel_contracts::ph1rem::ReminderState::Canceled
                    | selene_kernel_contracts::ph1rem::ReminderState::Completed
                    | selene_kernel_contracts::ph1rem::ReminderState::Failed
            )
        })
        .map(|row| row.resolved_due_at.0.to_string())
        .unwrap_or_else(|| "none".to_string());

    let mut extracted_fields = vec![
        ToolStructuredField {
            key: "actor_user_id".to_string(),
            value: actor_user_id.as_str().to_string(),
        },
        ToolStructuredField {
            key: "reminder_count".to_string(),
            value: reminders.len().to_string(),
        },
        ToolStructuredField {
            key: "active_reminder_count".to_string(),
            value: active_count.to_string(),
        },
        ToolStructuredField {
            key: "inactive_reminder_count".to_string(),
            value: reminders.len().saturating_sub(active_count).to_string(),
        },
        ToolStructuredField {
            key: "next_active_due_at_ns".to_string(),
            value: next_active_due_at,
        },
    ];
    for (index, row) in reminders.iter().take(5).enumerate() {
        let reminder_text = if row.reminder_request_text.chars().count() > 160 {
            format!(
                "{}...",
                row.reminder_request_text
                    .chars()
                    .take(157)
                    .collect::<String>()
            )
        } else {
            row.reminder_request_text.clone()
        };
        let channel_summary = if row.channel_preferences.is_empty() {
            "NONE".to_string()
        } else {
            row.channel_preferences
                .iter()
                .map(|channel| format!("{channel:?}").to_ascii_uppercase())
                .collect::<Vec<_>>()
                .join(",")
        };
        extracted_fields.push(ToolStructuredField {
            key: format!("reminder_{}", index + 1),
            value: format!(
                "id={} state={} type={} due_at_ns={} channels={} request={}",
                row.reminder_id.as_str(),
                format!("{:?}", row.state).to_ascii_uppercase(),
                format!("{:?}", row.reminder_type).to_ascii_uppercase(),
                row.resolved_due_at.0,
                channel_summary,
                reminder_text,
            ),
        });
    }

    let citations = if reminders.is_empty() {
        vec![ToolTextSnippet {
            title: "Reminder ledger is empty".to_string(),
            snippet: format!(
                "No reminder rows are currently recorded for user {}.",
                actor_user_id.as_str()
            ),
            url: format!(
                "https://selene.local/ph1f/reminders/user/{}",
                actor_user_id.as_str()
            ),
        }]
    } else {
        reminders
            .iter()
            .take(5)
            .map(|row| {
                let snippet_request = if row.reminder_request_text.chars().count() > 160 {
                    format!(
                        "{}...",
                        row.reminder_request_text.chars().take(157).collect::<String>()
                    )
                } else {
                    row.reminder_request_text.clone()
                };
                let recurrence = row
                    .recurrence_rule
                    .clone()
                    .unwrap_or_else(|| "none".to_string());
                ToolTextSnippet {
                    title: format!("Reminder {}", row.reminder_id.as_str()),
                    snippet: format!(
                        "request={} | state={} | type={} | due_at_ns={} | desired_time={} | recurrence={}",
                        snippet_request,
                        format!("{:?}", row.state).to_ascii_uppercase(),
                        format!("{:?}", row.reminder_type).to_ascii_uppercase(),
                        row.resolved_due_at.0,
                        row.desired_time_text,
                        recurrence,
                    ),
                    url: format!(
                        "https://selene.local/ph1f/reminders/{}/{}",
                        row.tenant_id.as_str(),
                        row.reminder_id.as_str()
                    ),
                }
            })
            .collect()
    };

    let mut sources = reminders
        .iter()
        .take(5)
        .map(|row| SourceRef {
            title: format!("PH1.F reminder {}", row.reminder_id.as_str()),
            url: format!(
                "https://selene.local/ph1f/reminders/{}/{}",
                row.tenant_id.as_str(),
                row.reminder_id.as_str()
            ),
        })
        .collect::<Vec<_>>();
    if sources.is_empty() {
        sources.push(SourceRef {
            title: "PH1.F reminder ledger".to_string(),
            url: format!(
                "https://selene.local/ph1f/reminders/user/{}",
                actor_user_id.as_str()
            ),
        });
    }

    let summary = if reminders.is_empty() {
        format!(
            "No reminders are currently recorded for user {}.",
            actor_user_id.as_str()
        )
    } else {
        format!(
            "{} reminder rows found for user {}; {} remain active.",
            reminders.len(),
            actor_user_id.as_str(),
            active_count
        )
    };

    let source_metadata = SourceMetadata {
        schema_version: selene_kernel_contracts::ph1e::PH1E_CONTRACT_VERSION,
        provider_hint: Some("ph1f_reminder_registry".to_string()),
        retrieved_at_unix_ms: 1_700_000_000_000,
        sources,
    };
    let tool_result = ToolResult::ConnectorQuery {
        summary,
        extracted_fields,
        citations,
    };
    let response = ToolResponse::ok_v1(
        tool_request.request_id,
        tool_request.query_hash,
        tool_result,
        source_metadata,
        None,
        ReasonCodeId(0x4500_0002),
        CacheStatus::Bypassed,
    )
    .map_err(StorageError::ContractViolation)?;
    Ok(Some(response))
}

fn maybe_build_message_policy_tool_response(
    store: &Ph1fStore,
    actor_user_id: &UserId,
    tool_request: &ToolRequest,
) -> Result<Option<ToolResponse>, StorageError> {
    if !matches!(tool_request.tool_name, ToolName::ConnectorQuery) {
        return Ok(None);
    }
    if !is_message_policy_query(tool_request.query.as_str()) {
        return Ok(None);
    }

    let tenant_id = resolve_actor_single_tenant(store, actor_user_id)?;
    let changes = store.bcast_policy_changes_for_tenant(&tenant_id, 10);
    let non_urgent_wait_seconds = store.bcast_non_urgent_wait_seconds_for_tenant(&tenant_id);
    let urgent_followup_immediate = store.bcast_urgent_followup_immediate_for_tenant(&tenant_id);
    let max_followup_attempts = store.bcast_max_followup_attempts_for_tenant(&tenant_id);
    let reminder_default_time = store
        .bcast_reminder_default_time_for_tenant(&tenant_id)
        .unwrap_or("unset")
        .to_string();
    let current = store.bcast_policy_current_row(&tenant_id);

    let non_urgent_updated_ns =
        latest_setting_update_ns(&changes, BcastPolicySettingKey::NonUrgentWaitSeconds);
    let urgent_updated_ns =
        latest_setting_update_ns(&changes, BcastPolicySettingKey::UrgentFollowupMode);
    let max_followup_updated_ns =
        latest_setting_update_ns(&changes, BcastPolicySettingKey::MaxFollowupAttempts);
    let reminder_default_updated_ns =
        latest_setting_update_ns(&changes, BcastPolicySettingKey::ReminderDefaultTime);

    let urgent_mode = if urgent_followup_immediate {
        "immediate"
    } else {
        "wait"
    };
    let current_provenance = format!(
        "ph1f.bcast_policy_current tenant={} path=/ph1f/bcast-policy/{}/current",
        tenant_id.as_str(),
        tenant_id.as_str(),
    );
    let first_change_summary = changes.first().map(|row| {
        format!(
            "setting={} {}->{} by={} at_ns={} reason_code={} idempotency_key={}",
            row.setting_key.as_str(),
            row.old_value,
            row.new_value,
            row.updated_by_user_id.as_str(),
            row.created_at.0,
            row.reason_code.0,
            row.idempotency_key,
        )
    });

    let mut extracted_fields = vec![
        ToolStructuredField {
            key: "non_urgent_wait_seconds".to_string(),
            value: non_urgent_wait_seconds.to_string(),
        },
        ToolStructuredField {
            key: "non_urgent_wait_updated_at_ns".to_string(),
            value: non_urgent_updated_ns,
        },
        ToolStructuredField {
            key: "urgent_followup_mode".to_string(),
            value: urgent_mode.to_string(),
        },
        ToolStructuredField {
            key: "urgent_followup_updated_at_ns".to_string(),
            value: urgent_updated_ns,
        },
        ToolStructuredField {
            key: "max_followup_attempts".to_string(),
            value: max_followup_attempts.to_string(),
        },
        ToolStructuredField {
            key: "max_followup_attempts_updated_at_ns".to_string(),
            value: max_followup_updated_ns,
        },
        ToolStructuredField {
            key: "reminder_default_time".to_string(),
            value: reminder_default_time,
        },
        ToolStructuredField {
            key: "reminder_default_time_updated_at_ns".to_string(),
            value: reminder_default_updated_ns,
        },
        ToolStructuredField {
            key: "policy_current_provenance".to_string(),
            value: current_provenance,
        },
        ToolStructuredField {
            key: "policy_change_1".to_string(),
            value: first_change_summary
                .unwrap_or_else(|| "no policy change rows recorded".to_string()),
        },
    ];

    if let Some(current_row) = current {
        extracted_fields.push(ToolStructuredField {
            key: "policy_updated_by_user_id".to_string(),
            value: current_row.updated_by_user_id.as_str().to_string(),
        });
        extracted_fields.push(ToolStructuredField {
            key: "policy_version".to_string(),
            value: current_row.policy_version.to_string(),
        });
    }
    extracted_fields.push(ToolStructuredField {
        key: "policy_change_count".to_string(),
        value: changes.len().to_string(),
    });

    let citations = if changes.is_empty() {
        vec![ToolTextSnippet {
            title: "No policy changes recorded".to_string(),
            snippet: format!(
                "Tenant {} is using default BCAST policy values.",
                tenant_id.as_str()
            ),
            url: format!(
                "https://selene.local/ph1f/bcast-policy/{}/ledger",
                tenant_id.as_str()
            ),
        }]
    } else {
        changes
            .iter()
            .take(5)
            .map(|row| ToolTextSnippet {
                title: format!("Policy change {}", row.setting_key.as_str()),
                snippet: format!(
                    "{} -> {} | by={} | at_ns={} | reason_code={} | idempotency_key={}",
                    row.old_value,
                    row.new_value,
                    row.updated_by_user_id.as_str(),
                    row.created_at.0,
                    row.reason_code.0,
                    row.idempotency_key,
                ),
                url: format!(
                    "https://selene.local/ph1f/bcast-policy/{}/event/{}",
                    row.tenant_id.as_str(),
                    row.bcast_policy_event_id
                ),
            })
            .collect()
    };

    let source_metadata = SourceMetadata {
        schema_version: selene_kernel_contracts::ph1e::PH1E_CONTRACT_VERSION,
        provider_hint: Some("ph1f_bcast_policy_registry".to_string()),
        retrieved_at_unix_ms: 1_700_000_000_000,
        sources: vec![
            SourceRef {
                title: "PH1.F current policy projection".to_string(),
                url: format!(
                    "https://selene.local/ph1f/bcast-policy/{}/current",
                    tenant_id.as_str()
                ),
            },
            SourceRef {
                title: "PH1.F policy change ledger".to_string(),
                url: format!(
                    "https://selene.local/ph1f/bcast-policy/{}/ledger",
                    tenant_id.as_str()
                ),
            },
        ],
    };
    let tool_result = ToolResult::ConnectorQuery {
        summary: format!(
            "Message policy settings for tenant {} with {} recent change rows.",
            tenant_id.as_str(),
            changes.len()
        ),
        extracted_fields,
        citations,
    };
    let response = ToolResponse::ok_v1(
        tool_request.request_id,
        tool_request.query_hash,
        tool_result,
        source_metadata,
        None,
        ReasonCodeId(0x4500_0001),
        CacheStatus::Bypassed,
    )
    .map_err(StorageError::ContractViolation)?;
    Ok(Some(response))
}

fn latest_setting_update_ns(
    changes: &[BcastPolicyLedgerRow],
    setting_key: BcastPolicySettingKey,
) -> String {
    changes
        .iter()
        .find(|row| row.setting_key == setting_key)
        .map(|row| row.created_at.0.to_string())
        .unwrap_or_else(|| "default".to_string())
}

fn is_message_policy_query(query: &str) -> bool {
    let lower = query.to_ascii_lowercase();
    lower.contains("message policy")
        || lower.contains("policy settings")
        || lower.contains("list my policies")
        || lower.contains("policy change")
        || lower.contains("policy audit")
}

fn is_list_reminders_query(query: &str) -> bool {
    let lower = query.to_ascii_lowercase();
    lower.contains("reminder")
        && (lower.contains("list")
            || lower.contains("show")
            || lower.contains("what")
            || lower.contains("which")
            || lower.contains("upcoming"))
}

fn resolve_actor_single_tenant(
    store: &Ph1fStore,
    actor_user_id: &UserId,
) -> Result<TenantId, StorageError> {
    let mut inferred: Option<String> = None;
    for (tenant_id, user_id) in store.ph2access_instance_rows().keys() {
        if user_id != actor_user_id {
            continue;
        }
        if let Some(existing) = &inferred {
            if existing != tenant_id {
                return Err(StorageError::ContractViolation(
                    ContractViolation::InvalidValue {
                        field: "app_voice_turn_execution_outcome.tool_request.query",
                        reason: "message policy query requires a single tenant scope",
                    },
                ));
            }
        } else {
            inferred = Some(tenant_id.clone());
        }
    }
    let tenant = inferred.ok_or({
        StorageError::ContractViolation(ContractViolation::InvalidValue {
            field: "app_voice_turn_execution_outcome.tool_request.query",
            reason: "message policy query requires actor tenant access instance",
        })
    })?;
    TenantId::new(tenant).map_err(StorageError::ContractViolation)
}

fn normalized_tenant_scope_for_dev_intake(
    store: &Ph1fStore,
    actor_user_id: &UserId,
    actor_tenant_id: Option<&str>,
) -> Result<String, StorageError> {
    if let Some(tenant_id) = actor_tenant_id {
        return Ok(TenantId::new(tenant_id.to_string())
            .map_err(StorageError::ContractViolation)?
            .as_str()
            .to_string());
    }
    Ok(resolve_actor_single_tenant(store, actor_user_id)?
        .as_str()
        .to_string())
}

fn build_finder_run_request_for_simulation_intent(
    store: &Ph1fStore,
    actor_user_id: &UserId,
    actor_tenant_id: Option<&str>,
    packet: &AgentInputPacket,
) -> Result<Option<FinderRunRequest>, StorageError> {
    let Some(Ph1nResponse::IntentDraft(intent_draft)) = packet.nlp_output.as_ref() else {
        return Ok(None);
    };
    if !intent_type_requires_simulation_finder(intent_draft.intent_type) {
        return Ok(None);
    }

    let tenant_id = normalized_tenant_scope_for_dev_intake(store, actor_user_id, actor_tenant_id)?;
    let simulation_catalog_snapshot_version = packet.sim_catalog_snapshot_version.max(1);
    let transcript_text = packet
        .srl_repaired_transcript
        .clone()
        .or(packet.transcript_text.clone())
        .unwrap_or_else(|| intent_draft_transcript_fallback(intent_draft));
    let intent_family = finder_intent_family(intent_draft.intent_type);
    let simulation_catalog = match simulation_id_for_intent_draft_v1(intent_draft) {
        Ok(simulation_id) => match simulation_status_for_tenant(store, &tenant_id, simulation_id) {
            Some(status) => {
                let entry = FinderSimulationCatalogEntry::v1(
                    simulation_id.to_string(),
                    intent_family.clone(),
                    status,
                    100,
                    finder_access_actions_for_intent(intent_draft.intent_type),
                    finder_risk_tier_for_intent(intent_draft.intent_type),
                    finder_confirm_required_for_intent(intent_draft.intent_type),
                    FinderFallbackPolicy::Refuse,
                    finder_synonym_terms_from_transcript(&intent_family, &transcript_text),
                    finder_required_field_specs_from_intent(intent_draft)?,
                    vec!["runtime.default".to_string()],
                )
                .map_err(StorageError::ContractViolation)?;
                vec![entry]
            }
            None => Vec::new(),
        },
        Err(_) => Vec::new(),
    };

    let run_request = FinderRunRequest::v1(
        tenant_id,
        actor_user_id.as_str().to_string(),
        packet.correlation_id,
        packet.turn_id,
        packet
            .thread_key
            .clone()
            .unwrap_or_else(|| format!("corr:{}:thread", packet.correlation_id)),
        packet.now,
        transcript_text,
        packet.sim_catalog_snapshot_hash.clone(),
        simulation_catalog_snapshot_version,
        simulation_catalog,
        Vec::<FinderGoldMapping>::new(),
        10_000,
        7_500,
        7_500,
        0,
        0,
        0,
        1,
        "runtime".to_string(),
        5_000,
        5_000,
        5_000,
        5_000,
        2_500,
        "tenant_only".to_string(),
        "{\"required\":[]}".to_string(),
        vec!["AT-AGENT-INGRESS-FINDER".to_string()],
    )
    .map_err(StorageError::ContractViolation)?;
    Ok(Some(run_request))
}

fn finder_required_field_specs_from_intent(
    intent_draft: &IntentDraft,
) -> Result<Vec<FinderFieldSpec>, StorageError> {
    let mut specs = Vec::new();
    for missing_field in &intent_draft.required_fields_missing {
        let field_name = finder_field_name(*missing_field);
        let detector_terms = finder_detector_terms_for_field(intent_draft, *missing_field);
        let spec = FinderFieldSpec::required_v1(
            field_name.clone(),
            detector_terms,
            7_500,
            7_500,
            6_500,
            finder_clarify_question(*missing_field),
            finder_allowed_answer_formats(*missing_field),
        )
        .map_err(StorageError::ContractViolation)?;
        specs.push(spec);
    }
    Ok(specs)
}

fn finder_detector_terms_for_field(intent_draft: &IntentDraft, key: FieldKey) -> Vec<String> {
    let mut terms = intent_draft
        .fields
        .iter()
        .filter(|field| field.key == key)
        .filter_map(|field| {
            field
                .value
                .normalized_value
                .clone()
                .or(Some(field.value.original_span.clone()))
        })
        .map(|value| value.trim().to_ascii_lowercase())
        .filter(|value| !value.is_empty())
        .collect::<Vec<_>>();
    if terms.is_empty() {
        terms.push(finder_field_name(key));
    }
    terms.sort();
    terms.dedup();
    terms
}

fn finder_field_name(key: FieldKey) -> String {
    format!("{:?}", key).to_ascii_lowercase()
}

fn finder_clarify_question(key: FieldKey) -> String {
    match key {
        FieldKey::RecipientContact => "What contact should I use?".to_string(),
        FieldKey::Recipient => "Who is the recipient?".to_string(),
        FieldKey::Task => "What should I do?".to_string(),
        FieldKey::When => "What exact date and time should I use?".to_string(),
        _ => format!("What is the {}?", finder_field_name(key)),
    }
}

fn finder_allowed_answer_formats(key: FieldKey) -> Vec<String> {
    match key {
        FieldKey::RecipientContact => {
            vec![
                "+14155550100".to_string(),
                "tom@example.invalid".to_string(),
            ]
        }
        FieldKey::When => vec![
            "Tomorrow at 7 PM".to_string(),
            "2026-03-02T19:00".to_string(),
        ],
        _ => vec!["Short text".to_string(), "Typed value".to_string()],
    }
}

fn intent_draft_transcript_fallback(intent_draft: &IntentDraft) -> String {
    let mut parts = vec![finder_intent_family(intent_draft.intent_type)];
    parts.extend(intent_draft.fields.iter().filter_map(|field| {
        field
            .value
            .normalized_value
            .clone()
            .or(Some(field.value.original_span.clone()))
    }));
    parts.extend(
        intent_draft
            .evidence_spans
            .iter()
            .map(|span| span.verbatim_excerpt.clone()),
    );
    parts
        .into_iter()
        .map(|part| part.trim().to_string())
        .filter(|part| !part.is_empty())
        .collect::<Vec<_>>()
        .join(" ")
}

fn finder_synonym_terms_from_transcript(intent_family: &str, transcript: &str) -> Vec<String> {
    let mut terms = transcript
        .split(|ch: char| !ch.is_ascii_alphanumeric())
        .map(|term| term.trim().to_ascii_lowercase())
        .filter(|term| term.len() >= 3)
        .take(16)
        .collect::<Vec<_>>();
    terms.push(intent_family.to_ascii_lowercase());
    terms.sort();
    terms.dedup();
    if terms.is_empty() {
        vec![intent_family.to_ascii_lowercase()]
    } else {
        terms
    }
}

fn simulation_status_for_tenant(
    store: &Ph1fStore,
    tenant_id: &str,
    simulation_id: &str,
) -> Option<SimulationStatus> {
    let tenant_id = TenantId::new(tenant_id.to_string()).ok()?;
    let simulation_id =
        selene_kernel_contracts::ph1simcat::SimulationId::new(simulation_id.to_string()).ok()?;
    store
        .simulation_catalog_current()
        .get(&(tenant_id, simulation_id))
        .map(|row| row.status)
}

fn finder_intent_family(intent_type: IntentType) -> String {
    format!("{intent_type:?}").to_ascii_lowercase()
}

fn finder_confirm_required_for_intent(intent_type: IntentType) -> bool {
    !matches!(
        intent_type,
        IntentType::MemoryRememberRequest | IntentType::MemoryQuery
    )
}

fn finder_risk_tier_for_intent(intent_type: IntentType) -> FinderRiskTier {
    if matches!(
        intent_type,
        IntentType::CreateInviteLink | IntentType::SendMoney
    ) {
        FinderRiskTier::High
    } else {
        FinderRiskTier::Medium
    }
}

fn finder_access_actions_for_intent(intent_type: IntentType) -> Vec<String> {
    let action = match intent_type {
        IntentType::CreateInviteLink => "LINK_SEND_INVITE",
        IntentType::SetReminder
        | IntentType::UpdateReminder
        | IntentType::CancelReminder
        | IntentType::CreateCalendarEvent => "REMINDER_SCHEDULE_ACCESS",
        IntentType::UpdateBcastWaitPolicy => "BCAST_WAIT_POLICY_UPDATE",
        IntentType::UpdateBcastUrgentFollowupPolicy => "BCAST_URGENT_FOLLOWUP_POLICY_UPDATE",
        IntentType::CapreqManage => "CAPREQ_MANAGE",
        IntentType::AccessSchemaManage => "ACCESS_SCHEMA_MANAGE",
        IntentType::AccessEscalationVote => "ACCESS_ESCALATION_VOTE",
        IntentType::AccessInstanceCompileRefresh => "ACCESS_INSTANCE_COMPILE",
        _ => "SIMULATION_EXECUTE",
    };
    vec![action.to_string()]
}

fn intent_type_requires_simulation_finder(intent_type: IntentType) -> bool {
    !matches!(
        intent_type,
        IntentType::TimeQuery
            | IntentType::WeatherQuery
            | IntentType::WebSearchQuery
            | IntentType::NewsQuery
            | IntentType::UrlFetchAndCiteQuery
            | IntentType::DocumentUnderstandQuery
            | IntentType::PhotoUnderstandQuery
            | IntentType::DataAnalysisQuery
            | IntentType::DeepResearchQuery
            | IntentType::RecordModeQuery
            | IntentType::ConnectorQuery
            | IntentType::ListReminders
            | IntentType::Continue
            | IntentType::MoreDetail
    )
}

fn build_ph1x_request_from_agent_input_packet(
    app_platform: AppPlatform,
    packet: &AgentInputPacket,
) -> Result<Ph1xRequest, StorageError> {
    let effective_policy_context_ref =
        merge_thread_policy_context(packet.policy_context_ref, &packet.thread_state);
    let voice_identity_assertion = canonical_agent_packet_voice_identity_assertion(packet)?.clone();
    let mut req = Ph1xRequest::v1(
        packet.correlation_id,
        packet.turn_id,
        packet.now,
        packet.thread_state.clone(),
        packet.session_state,
        IdentityContext::Voice(voice_identity_assertion),
        effective_policy_context_ref,
        packet.memory_candidates.clone(),
        packet.confirm_answer,
        packet.nlp_output.clone(),
        packet.tool_response.clone(),
        packet.interruption.clone(),
        packet.language_hint.clone(),
        packet.last_failure_reason_code,
    )
    .map_err(StorageError::ContractViolation)?;
    req = req
        .with_language_packet(packet.language_packet.clone())
        .map_err(StorageError::ContractViolation)?;
    let step_up_capabilities = match app_platform {
        AppPlatform::Ios | AppPlatform::Android | AppPlatform::Tablet => {
            StepUpCapabilities::v1(true, true)
        }
        AppPlatform::Desktop => StepUpCapabilities::v1(false, true),
    };
    req = req
        .with_step_up_capabilities(Some(step_up_capabilities))
        .map_err(StorageError::ContractViolation)?;
    req = req
        .with_identity_prompt_scope_key(packet.identity_prompt_scope_key.clone())
        .map_err(StorageError::ContractViolation)?;
    Ok(req)
}

fn canonical_agent_packet_voice_identity_assertion(
    packet: &AgentInputPacket,
) -> Result<&Ph1VoiceIdResponse, StorageError> {
    let canonical_voice_identity_assertion = packet
        .runtime_execution_envelope
        .as_ref()
        .and_then(|runtime_execution_envelope| {
            runtime_execution_envelope.voice_identity_assertion.as_ref()
        })
        .ok_or(StorageError::ContractViolation(
            ContractViolation::InvalidValue {
                field: "agent_input_packet.runtime_execution_envelope.voice_identity_assertion",
                reason: "must carry canonical embedded voice identity assertion for ph1x request",
            },
        ))?;
    if packet.voice_identity_assertion != *canonical_voice_identity_assertion {
        return Err(StorageError::ContractViolation(
            ContractViolation::InvalidValue {
                field: "agent_input_packet.voice_identity_assertion",
                reason: "must match canonical embedded voice identity assertion for ph1x request",
            },
        ));
    }
    Ok(canonical_voice_identity_assertion)
}

fn transcript_text_from_nlp_output(nlp_output: Option<&Ph1nResponse>) -> Option<String> {
    match nlp_output {
        Some(Ph1nResponse::Chat(chat)) => Some(chat.response_text.clone()),
        Some(Ph1nResponse::IntentDraft(draft)) => Some(intent_draft_transcript_fallback(draft)),
        _ => None,
    }
}

fn simulation_catalog_snapshot_for_agent_input(
    store: &Ph1fStore,
    tenant_id: Option<&str>,
) -> (String, u64) {
    let mut rows: Vec<String> = store
        .simulation_catalog_current()
        .iter()
        .filter(|((tenant, _), _)| {
            tenant_id
                .map(|value| tenant.as_str() == value)
                .unwrap_or(true)
        })
        .map(|((tenant, simulation_id), row)| {
            format!(
                "{}|{}|{}|{:?}|{:?}|{}",
                tenant.as_str(),
                simulation_id.as_str(),
                row.simulation_version.0,
                row.simulation_type,
                row.status,
                row.source_event_id
            )
        })
        .collect();
    rows.sort();
    let snapshot_text = if rows.is_empty() {
        "simcat:empty".to_string()
    } else {
        rows.join("\n")
    };
    let hash = agent_hash_hex(&snapshot_text);
    let version = store
        .simulation_catalog_events()
        .iter()
        .filter(|row| {
            tenant_id
                .map(|value| row.tenant_id.as_str() == value)
                .unwrap_or(true)
        })
        .map(|row| row.simulation_catalog_event_id)
        .max()
        .unwrap_or(0);
    (hash, version)
}

#[allow(clippy::too_many_arguments)]
fn agent_input_packet_hash_hex(
    correlation_id: CorrelationId,
    turn_id: TurnId,
    now: MonotonicTimeNs,
    trace_id: &str,
    transcript_text: Option<&str>,
    language_hint: Option<&str>,
    session_id: Option<selene_kernel_contracts::ph1l::SessionId>,
    session_state: SessionState,
    thread_key: Option<&str>,
    thread_state: &ThreadState,
    memory_candidates: &[MemoryCandidate],
    sim_catalog_snapshot_version: u64,
    sim_catalog_snapshot_hash: &str,
    identity_prompt_scope_key: Option<&str>,
    language_packet: Option<&LanguagePacket>,
) -> String {
    let mut lines = vec![
        format!("corr={}", correlation_id.0),
        format!("turn={}", turn_id.0),
        format!("now={}", now.0),
        format!("trace={trace_id}"),
        format!("session={}", session_id.map(|v| v.0).unwrap_or(0)),
        format!("session_state={session_state:?}"),
        format!("thread_key={}", thread_key.unwrap_or("none")),
        format!("thread_pending={}", thread_state.pending.is_some()),
        format!(
            "thread_project={}",
            thread_state.project_id.as_deref().unwrap_or("none")
        ),
        format!(
            "identity_prompt_scope_key={}",
            identity_prompt_scope_key.unwrap_or("none")
        ),
        format!(
            "sim_catalog={}#{}",
            sim_catalog_snapshot_hash, sim_catalog_snapshot_version
        ),
        format!(
            "transcript={}",
            transcript_text
                .map(truncate_for_packet_hash)
                .unwrap_or_default()
        ),
        format!("lang={}", language_hint.unwrap_or("none")),
        format!(
            "language_packet={}",
            language_packet
                .map(language_packet_hash_component)
                .unwrap_or_else(|| "none".to_string())
        ),
    ];
    lines.extend(memory_candidates.iter().map(|candidate| {
        format!(
            "mem:{}:{}:{}",
            candidate.memory_key.as_str(),
            candidate.memory_value.verbatim,
            candidate.last_seen_at.0
        )
    }));
    lines.sort();
    agent_hash_hex(&lines.join("\n"))
}

fn language_packet_hash_component(packet: &LanguagePacket) -> String {
    format!(
        "{}>{};conf={};mixed={};clarify={};scope={:?}",
        packet.input_language_primary,
        packet.output_language_selected,
        packet.input_language_confidence,
        packet.mixed_language_detected,
        packet.clarification_required,
        packet.language_switch_scope
    )
}

fn build_language_packet_from_agent_fields(
    transcript_text: Option<&str>,
    language_hint: Option<&str>,
) -> Result<Option<LanguagePacket>, StorageError> {
    let Some(text) = transcript_text
        .map(str::trim)
        .filter(|text| !text.is_empty())
    else {
        return Ok(None);
    };
    let detected = detect_language_packet_languages(text, language_hint);
    let switch_requested = detects_language_switch_request(text);
    let output_language = explicit_output_language(text)
        .map(str::to_string)
        .unwrap_or_else(|| detected.primary.clone());
    let packet = LanguagePacket::v1(
        detected.primary,
        detected.candidates,
        detected.confidence_bps,
        output_language,
        if switch_requested {
            "explicit_user_language_instruction".to_string()
        } else {
            "same_language_continuity".to_string()
        },
        detected.script,
        detected.mixed,
        switch_requested,
        LanguageSwitchScope::ThisTurn,
        "not_measured".to_string(),
        broken_language_risk(text).to_string(),
        detected.confidence_bps < 5_000,
        vec!["text_detector".to_string(), "locale_hint".to_string()],
    )
    .map_err(StorageError::ContractViolation)?;
    Ok(Some(packet))
}

struct DetectedLanguagePacket {
    primary: String,
    candidates: Vec<String>,
    confidence_bps: u16,
    script: String,
    mixed: bool,
}

fn detect_language_packet_languages(
    text: &str,
    language_hint: Option<&str>,
) -> DetectedLanguagePacket {
    let has_cjk = text.chars().any(is_cjk_char);
    let has_ascii_alpha = text.chars().any(|ch| ch.is_ascii_alphabetic());
    let hint = language_hint.unwrap_or_default().to_ascii_lowercase();
    let mixed = has_cjk && has_ascii_alpha;
    let mut candidates = Vec::new();
    if has_cjk {
        candidates.push("zh".to_string());
    }
    if has_ascii_alpha {
        candidates.push("en".to_string());
    }
    if candidates.is_empty() {
        if hint.starts_with("zh") {
            candidates.push("zh".to_string());
        } else {
            candidates.push("en".to_string());
        }
    }
    candidates.sort();
    candidates.dedup();
    let primary = if explicit_output_language(text).is_some() {
        explicit_output_language(text).unwrap_or("en").to_string()
    } else if has_cjk {
        "zh".to_string()
    } else if hint.starts_with("zh") {
        "zh".to_string()
    } else {
        "en".to_string()
    };
    let confidence_bps = if text.contains("???") || text.trim().len() <= 1 {
        4_000
    } else if mixed {
        8_500
    } else if has_cjk || has_ascii_alpha {
        9_000
    } else {
        6_000
    };
    DetectedLanguagePacket {
        primary,
        candidates,
        confidence_bps,
        script: detect_language_script(text).to_string(),
        mixed,
    }
}

fn is_cjk_char(ch: char) -> bool {
    ('\u{4e00}'..='\u{9fff}').contains(&ch)
        || ('\u{3400}'..='\u{4dbf}').contains(&ch)
        || ('\u{f900}'..='\u{faff}').contains(&ch)
}

fn detect_language_script(text: &str) -> &'static str {
    let has_cjk = text.chars().any(is_cjk_char);
    let has_ascii = text.chars().any(|ch| ch.is_ascii_alphabetic());
    let has_traditional_markers = text.chars().any(|ch| {
        matches!(
            ch,
            '現' | '幾' | '點' | '這' | '個' | '後' | '氣' | '麼' | '簡' | '體' | '請'
        )
    });
    let has_simplified_markers = text.chars().any(|ch| {
        matches!(
            ch,
            '现' | '几' | '点' | '这' | '个' | '后' | '气' | '么' | '简' | '体' | '请'
        )
    });
    match (
        has_cjk,
        has_ascii,
        has_traditional_markers,
        has_simplified_markers,
    ) {
        (true, true, true, _) => "mixed-han-traditional-latin",
        (true, true, _, true) => "mixed-han-simplified-latin",
        (true, true, _, _) => "mixed-han-latin",
        (true, false, true, _) => "han-traditional",
        (true, false, _, true) => "han-simplified",
        (true, false, _, _) => "han",
        (false, true, _, _) => "latin",
        _ => "unknown",
    }
}

fn explicit_output_language(text: &str) -> Option<&'static str> {
    let lower = text.to_ascii_lowercase();
    if lower.contains("answer in chinese")
        || lower.contains("speak chinese")
        || lower.contains("use chinese")
        || text.contains("用中文")
        || text.contains("中文回答")
    {
        Some("zh")
    } else if lower.contains("answer in english")
        || lower.contains("speak english")
        || lower.contains("use english")
        || lower.contains("in simple english")
        || text.contains("用英文")
        || text.contains("英文回答")
    {
        Some("en")
    } else {
        None
    }
}

fn detects_language_switch_request(text: &str) -> bool {
    explicit_output_language(text).is_some()
}

fn broken_language_risk(text: &str) -> &'static str {
    let lower = text.to_ascii_lowercase();
    if lower.contains("what now") || lower.split_whitespace().count() <= 3 {
        "possible"
    } else {
        "not_measured"
    }
}

fn truncate_for_packet_hash(text: &str) -> String {
    const MAX: usize = 128;
    if text.len() <= MAX {
        return text.to_string();
    }
    let mut end = MAX;
    while end > 0 && !text.is_char_boundary(end) {
        end -= 1;
    }
    text[..end].to_string()
}

fn agent_hash_hex(value: &str) -> String {
    // FNV-1a 64-bit: deterministic and platform-independent.
    const OFFSET: u64 = 0xcbf29ce484222325;
    const PRIME: u64 = 0x100000001b3;
    let mut hash = OFFSET;
    for byte in value.as_bytes() {
        hash ^= *byte as u64;
        hash = hash.wrapping_mul(PRIME);
    }
    format!("{hash:016x}")
}

fn build_tool_followup_ph1x_request(
    base_request: &Ph1xRequest,
    dispatch_response: &Ph1xResponse,
    tool_response: ToolResponse,
) -> Result<Ph1xRequest, StorageError> {
    let mut req = Ph1xRequest::v1(
        base_request.correlation_id,
        base_request.turn_id,
        base_request.now,
        dispatch_response.thread_state.clone(),
        base_request.session_state,
        base_request.identity_context.clone(),
        base_request.policy_context_ref,
        base_request.memory_candidates.clone(),
        None,
        None,
        Some(tool_response),
        None,
        base_request.locale.clone(),
        None,
    )
    .map_err(StorageError::ContractViolation)?;
    req = req
        .with_step_up_capabilities(base_request.step_up_capabilities)
        .map_err(StorageError::ContractViolation)?;
    req = req
        .with_identity_prompt_scope_key(base_request.identity_prompt_scope_key.clone())
        .map_err(StorageError::ContractViolation)?;
    req = req
        .with_language_packet(base_request.language_packet.clone())
        .map_err(StorageError::ContractViolation)?;
    Ok(req)
}

fn append_app_ingress_tool_provenance(
    response_text: String,
    tool_response: &ToolResponse,
) -> String {
    let should_append = tool_response.tool_status == ToolStatus::Ok
        && !matches!(
            tool_response.tool_result.as_ref(),
            Some(ToolResult::Time { .. } | ToolResult::Weather { .. }) | None
        );
    if !should_append || response_text.contains("Retrieved at (unix_ms):") {
        return response_text;
    }

    let Some(source_metadata) = tool_response.source_metadata.as_ref() else {
        return response_text;
    };

    let mut text = response_text.trim_end().to_string();
    if !text.is_empty() {
        text.push('\n');
    }
    text.push_str(&format!(
        "Retrieved at (unix_ms): {}",
        source_metadata.retrieved_at_unix_ms
    ));
    text
}

fn merge_thread_policy_context(
    base: PolicyContextRef,
    thread_state: &ThreadState,
) -> PolicyContextRef {
    let mut privacy_mode = base.privacy_mode;
    let mut do_not_disturb = base.do_not_disturb;
    let mut safety_tier = base.safety_tier;
    if let Some(flags) = thread_state.thread_policy_flags {
        privacy_mode |= flags.force_privacy_mode;
        do_not_disturb |= flags.force_do_not_disturb;
        if flags.force_strict_safety {
            safety_tier = SafetyTier::Strict;
        }
    }
    PolicyContextRef::v1(privacy_mode, do_not_disturb, safety_tier)
}

fn memory_topic_hint_from_nlp_output(nlp_output: Option<&Ph1nResponse>) -> Option<String> {
    let Ph1nResponse::IntentDraft(draft) = nlp_output? else {
        return None;
    };
    [FieldKey::Recipient, FieldKey::Person, FieldKey::Task]
        .iter()
        .find_map(|key| {
            draft
                .fields
                .iter()
                .find(|field| field.key == *key)
                .and_then(|field| {
                    field
                        .value
                        .normalized_value
                        .as_ref()
                        .or(Some(&field.value.original_span))
                })
        })
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
}

