#[cfg(test)]
#[test]
fn session_recent_list_returns_recent_nonclosed_sessions_for_last_attached_device() {
    let runtime = AppServerIngressRuntime::default();
    let current_device_id = DeviceId::new("session_recent_current_device").unwrap();
    let other_device_id = DeviceId::new("session_recent_other_device").unwrap();
    let active_user_id = UserId::new("tenant_1:session_recent_active_actor").unwrap();
    let soft_closed_user_id = UserId::new("tenant_1:session_recent_soft_closed_actor").unwrap();
    let suspended_user_id = UserId::new("tenant_1:session_recent_suspended_actor").unwrap();
    let closed_user_id = UserId::new("tenant_1:session_recent_closed_actor").unwrap();
    let other_device_user_id = UserId::new("tenant_1:session_recent_other_device_actor").unwrap();
    let mut store = Ph1fStore::new_in_memory();

    seed_recent_session_record_for_last_attached_device_test(
        &mut store,
        SessionId(4_920),
        &active_user_id,
        &current_device_id,
        std::slice::from_ref(&current_device_id),
        &current_device_id,
        SessionState::Active,
        MonotonicTimeNs(120),
        Some(TurnId(920)),
    );
    seed_recent_session_record_for_last_attached_device_test(
        &mut store,
        SessionId(4_921),
        &soft_closed_user_id,
        &current_device_id,
        std::slice::from_ref(&current_device_id),
        &current_device_id,
        SessionState::SoftClosed,
        MonotonicTimeNs(220),
        Some(TurnId(921)),
    );
    seed_recent_session_record_for_last_attached_device_test(
        &mut store,
        SessionId(4_922),
        &suspended_user_id,
        &current_device_id,
        std::slice::from_ref(&current_device_id),
        &current_device_id,
        SessionState::Suspended,
        MonotonicTimeNs(180),
        Some(TurnId(922)),
    );
    seed_recent_session_record_for_last_attached_device_test(
        &mut store,
        SessionId(4_923),
        &closed_user_id,
        &current_device_id,
        std::slice::from_ref(&current_device_id),
        &current_device_id,
        SessionState::Closed,
        MonotonicTimeNs(260),
        Some(TurnId(923)),
    );
    seed_recent_session_record_for_last_attached_device_test(
        &mut store,
        SessionId(4_924),
        &other_device_user_id,
        &current_device_id,
        &[current_device_id.clone(), other_device_id.clone()],
        &other_device_id,
        SessionState::Active,
        MonotonicTimeNs(320),
        Some(TurnId(924)),
    );

    let outcome = runtime
        .run_session_recent_list(
            &store,
            AppSessionRecentListRequest::v1(
                CorrelationId(92_103),
                "session_recent_list".to_string(),
                current_device_id,
            )
            .unwrap(),
        )
        .unwrap();

    assert_eq!(outcome.sessions.len(), 3);
    assert_eq!(outcome.sessions[0].session_id, "4921");
    assert_eq!(outcome.sessions[1].session_id, "4922");
    assert_eq!(outcome.sessions[2].session_id, "4920");
    assert_eq!(outcome.sessions[0].session_state, SessionState::SoftClosed);
    assert_eq!(outcome.sessions[0].last_activity_at, 220);
    assert_eq!(outcome.sessions[0].last_turn_id.as_deref(), Some("921"));
    let (project_id, pinned_context_refs) = test_session_project_context_fixture();
    assert_eq!(
        outcome.sessions[0].project_id.as_deref(),
        Some(project_id.as_str())
    );
    assert_eq!(
        outcome.sessions[0].pinned_context_refs.as_deref(),
        Some(pinned_context_refs.as_slice())
    );
    assert!(outcome
        .sessions
        .iter()
        .all(|session| session.session_id != "4923"));
    assert!(outcome
        .sessions
        .iter()
        .all(|session| session.session_id != "4924"));
}

#[cfg(test)]
#[test]
fn session_posture_evidence_returns_current_device_fields_for_session() {
    let runtime = AppServerIngressRuntime::default();
    let current_device_id = DeviceId::new("session_posture_current_device").unwrap();
    let other_device_id = DeviceId::new("session_posture_other_device").unwrap();
    let user_id = UserId::new("tenant_1:session_posture_actor").unwrap();
    let session_id = SessionId(4_930);
    let mut store = Ph1fStore::new_in_memory();

    seed_recent_session_record_for_last_attached_device_test(
        &mut store,
        session_id,
        &user_id,
        &current_device_id,
        std::slice::from_ref(&current_device_id),
        &current_device_id,
        SessionState::SoftClosed,
        MonotonicTimeNs(330),
        Some(TurnId(930)),
    );

    let outcome = runtime
        .run_session_posture_evidence(
            &store,
            AppSessionPostureEvidenceRequest::v1(
                CorrelationId(92_104),
                "session_posture_evidence".to_string(),
                current_device_id.clone(),
                session_id,
            )
            .unwrap(),
        )
        .unwrap();

    let evidence = outcome.evidence;
    assert_eq!(evidence.session_id, "4930");
    assert_eq!(evidence.session_state, SessionState::SoftClosed);
    assert_eq!(evidence.last_turn_id.as_deref(), Some("930"));
    let (project_id, pinned_context_refs) = test_session_project_context_fixture();
    assert_eq!(evidence.project_id.as_deref(), Some(project_id.as_str()));
    assert_eq!(
        evidence.pinned_context_refs.as_deref(),
        Some(pinned_context_refs.as_slice())
    );
    assert_eq!(evidence.session_attach_outcome, None);
    assert_eq!(evidence.selected_thread_id, None);
    assert_eq!(evidence.selected_thread_title, None);
    assert_eq!(evidence.pending_work_order_id, None);
    assert_eq!(evidence.resume_tier, None);
    assert_eq!(evidence.resume_summary_bullets, None);
    assert_eq!(evidence.archived_user_turn_text, None);
    assert_eq!(evidence.archived_selene_turn_text, None);
    assert_eq!(evidence.recovery_mode, None);
    assert_eq!(evidence.reconciliation_decision, None);

    let err = runtime
        .run_session_posture_evidence(
            &store,
            AppSessionPostureEvidenceRequest::v1(
                CorrelationId(92_105),
                "session_posture_evidence_other_device".to_string(),
                other_device_id,
                session_id,
            )
            .unwrap(),
        )
        .expect_err("other device must fail closed");
    assert!(matches!(
        err,
        StorageError::ContractViolation(ContractViolation::InvalidValue {
            field: "app_session_posture_evidence_request.session_id",
            reason: "SESSION_NOT_AVAILABLE_FOR_DEVICE",
        })
    ));
}

