    #[test]
    fn at_identity_drift_01_cluster_drift_protected_voice_turn_fails_closed_with_explicit_cluster_drift_response(
    ) {
        let runtime = runtime_with_search_tool_fixtures_and_runtime_governance(
            RuntimeGovernanceRuntime::new(
                RuntimeGovernanceConfig::mvp_v1().with_policy_window(
                    selene_kernel_contracts::runtime_governance::GovernancePolicyWindow::v1(
                        "2026.03.08.v1".to_string(),
                        "2026.03.08.v1".to_string(),
                        "2026.04.01.v1".to_string(),
                    )
                    .unwrap(),
                ),
            ),
        );
        let actor_user_id = UserId::new("tenant_1:identity_cluster_drift_runtime_user").unwrap();
        let device_id = DeviceId::new("identity_cluster_drift_runtime_device_1").unwrap();
        let mut store = Ph1fStore::new_in_memory();
        seed_actor(&mut store, &actor_user_id, &device_id);
        let _ = runtime
            .observe_runtime_governance_node_policy_version("node_compat", Some("2026.04.01.v1"));

        let out = run_protected_chat_response_turn_with_identity_assertion(
            &runtime,
            &mut store,
            actor_user_id.clone(),
            device_id,
            confirmed_voice_assertion(actor_user_id),
            CorrelationId(9824),
            TurnId(9924),
        );

        assert_eq!(out.next_move, AppVoiceTurnNextMove::Refused);
        assert_eq!(
            out.response_text.as_deref(),
            Some("I can't continue because governance state is out of sync right now.")
        );
        assert_eq!(
            out.reason_code,
            out.ph1x_response
                .as_ref()
                .map(|response| response.reason_code)
        );
        let response_rows = store.ph1x_audit_rows(CorrelationId(9824));
        let row = find_ph1x_respond_row(&response_rows, "GOVERNANCE_CLUSTER_DRIFT_FAIL_CLOSED");
        assert_ph1x_fail_closed_respond_payload(
            &runtime,
            row,
            &out,
            "GOVERNANCE_CLUSTER_DRIFT_FAIL_CLOSED",
        );
        assert_eq!(
            ph1x_payload_value(row, "identity_cluster_drift_detected"),
            Some("true")
        );
    }

    #[test]
    fn at_identity_drift_01b_public_no_intent_answer_handoff_skips_governance_drift_without_weakening_protected_fail_closed(
    ) {
        let runtime = runtime_with_search_tool_fixtures();
        let actor_user_id = UserId::new("tenant_1:identity_public_no_intent_runtime_user").unwrap();
        let device_id = DeviceId::new("identity_public_no_intent_runtime_device_1").unwrap();
        let mut store = Ph1fStore::new_in_memory();
        seed_actor(&mut store, &actor_user_id, &device_id);
        let _ = runtime
            .observe_runtime_governance_node_policy_version("node_public", Some("2026.04.01.v1"));

        let pending = prepare_chat_response_turn_with_identity_assertion(
            &runtime,
            &mut store,
            actor_user_id.clone(),
            device_id.clone(),
            confirmed_voice_assertion(actor_user_id.clone()),
            CorrelationId(98241),
            TurnId(99241),
            "Okay. What would you like to do?".to_string(),
            ph1n_reason_codes::N_CHAT_NO_INTENT,
        );
        let public_out =
            finalize_pending_protected_chat_response_turn(&runtime, &mut store, pending)
                .expect("public no-intent answer handoff must remain lawful under drift");

        assert_eq!(public_out.next_move, AppVoiceTurnNextMove::Respond);
        let public_text = public_out
            .response_text
            .as_deref()
            .expect("public no-intent handoff should keep response text");
        assert!(!public_text.contains("governance state is out of sync"));
        assert!(!public_text.contains("policy versions are out of sync"));

        let protected_out = run_protected_chat_response_turn_with_identity_assertion(
            &runtime,
            &mut store,
            actor_user_id.clone(),
            device_id,
            confirmed_voice_assertion(actor_user_id),
            CorrelationId(98242),
            TurnId(99242),
        );
        assert_eq!(protected_out.next_move, AppVoiceTurnNextMove::Refused);
        assert!(
            protected_out
                .response_text
                .as_deref()
                .is_some_and(|text| text.contains("out of sync right now")),
            "protected drift path must still fail closed, got {:?}",
            protected_out.response_text
        );
    }

